import { each, stringIncludes } from '../../../utils/zcutils';
import { getAxisObject } from '../../../axis/axisutils';
import { fixBrushDirection } from './tools/selection-to-domain';
import { updateScaleByTransform } from './tools/transform-scale';

/**
 *
 * @param instanceMap
 * @param type
 */
export function ChartZoomDataFinder(instanceMap, type) {
    let eventManager = this,
        chart = eventManager.chart,
        plotZoom = instanceMap.instance,
        transform = plotZoom.getTransform(),
        zoomType = chart.systemConf.chart.zoom.type,
        zoomTypes = (instanceMap.types = instanceMap.types || { x: stringIncludes(zoomType, 'x'), y: stringIncludes(zoomType, 'y') });

    return getDomainInfoFromZoomTransform(transform, zoomTypes, chart);
}

/**
 *
 * @param transform
 * @param types
 * @param chart
 * @return {{}}
 */
function getDomainInfoFromZoomTransform(transform, types, chart) {
    let domainInfo = {},
        axisLength = { x: 1, y: chart.axes.y.groups.length };

    each(types, (enabled, type) => {
        if (enabled === true) {
            for (let i = 0; i < axisLength[type]; i++) {
                let axisInfo = getAxisObject(chart, type, i);
                if (!axisInfo.disabled) {
                    let { domain, range } = updateScaleByTransform(axisInfo, fixBrushDirection(type, chart.axes.rotated), transform);

                    let store = (domainInfo[type] = domainInfo[type] || []);
                    store.push({ domain, range, index: axisInfo.index });

                    axisInfo.domain = domain;
                    axisInfo.range = range;
                }
            }
        }
    });
    return domainInfo;
}
